const https = require('https');
const http = require('http');
const { URL } = require('url');

function fetchUrlMetadata(url, callback) {
  try {
    const parsedUrl = new URL(url);
    const protocol = parsedUrl.protocol === 'https:' ? https : http;
    
    const options = {
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
      },
      timeout: 10000
    };

    const req = protocol.get(url, options, (res) => {
      if (res.statusCode === 301 || res.statusCode === 302) {
        if (res.headers.location) {
          const redirectUrl = res.headers.location.startsWith('http') 
            ? res.headers.location 
            : new URL(res.headers.location, url).href;
          return fetchUrlMetadata(redirectUrl, callback);
        }
      }

      if (res.statusCode !== 200) {
        return callback(new Error(`HTTP ${res.statusCode}`), null);
      }

      let html = '';
      res.setEncoding('utf8');

      res.on('data', (chunk) => {
        html += chunk;
        if (html.length > 1048576) {
          res.destroy();
          return callback(new Error('Response too large'), null);
        }
      });

      res.on('end', () => {
        try {
          const metadata = parseMetadata(html);
          callback(null, metadata);
        } catch (error) {
          callback(error, null);
        }
      });
    });

    req.on('error', (error) => {
      callback(error, null);
    });

    req.on('timeout', () => {
      req.destroy();
      callback(new Error('Request timeout'), null);
    });

  } catch (error) {
    callback(error, null);
  }
}

function parseMetadata(html) {
  const metadata = {
    title: null,
    description: null,
    ogTitle: null,
    ogDescription: null,
    ogImage: null,
    ogUrl: null,
    ogType: null,
    ogSiteName: null
  };

  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = decodeHtml(titleMatch[1].trim());
  }

  const descMatch = html.match(/<meta\s+name=["']description["'][^>]*content=["']([^"']+)["']/i) ||
                    html.match(/<meta\s+content=["']([^"']+)["'][^>]*name=["']description["']/i);
  if (descMatch) {
    metadata.description = decodeHtml(descMatch[1].trim());
  }

  const ogTags = {
    'og:title': 'ogTitle',
    'og:description': 'ogDescription',
    'og:image': 'ogImage',
    'og:url': 'ogUrl',
    'og:type': 'ogType',
    'og:site_name': 'ogSiteName'
  };

  for (const [property, key] of Object.entries(ogTags)) {
    const pattern = new RegExp(`<meta\\s+property=["']${property}["'][^>]*content=["']([^"']+)["']`, 'i');
    const altPattern = new RegExp(`<meta\\s+content=["']([^"']+)["'][^>]*property=["']${property}["']`, 'i');
    
    const match = html.match(pattern) || html.match(altPattern);
    if (match) {
      metadata[key] = decodeHtml(match[1].trim());
    }
  }

  return metadata;
}

function decodeHtml(text) {
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&#x27;': "'",
    '&#x2F;': '/',
    '&#47;': '/'
  };

  return text.replace(/&[^;]+;/g, (entity) => entities[entity] || entity);
}

